// src/index.js
import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";
import App from "./App"; // Adjust this import name if your main layout file is named differently
import "./index.css"; // Keeps your original global styles intact

function Root() {
  // 1. Define global state tracking for Dark Theme
  const [darkMode, setDarkMode] = useState(false);

  // 2. Build the Material-UI theme dynamically based on state
  const theme = createTheme({
    palette: {
      mode: darkMode ? "dark" : "light",
      background: {
        default: darkMode ? "#121212" : "#ffffff",
        paper: darkMode ? "#1e1e1e" : "#ffffff",
      },
      text: {
        primary: darkMode ? "#ffffff" : "#000000",
        secondary: darkMode ? "#aaaaaa" : "#666666",
      },
    },
    // Optional: Overriding standard components to respect the theme global background
    components: {
      MuiSwitch: {
        styleOverrides: {
          switchBase: {
            // Adjusts switch styles if necessary
          },
        },
      },
    },
  });

  return (
    // 3. Wrap your root layout inside the theme provider engine
    <ThemeProvider theme={theme}>
      {/* CssBaseline guarantees the body background color responds to the theme switch */}
      <CssBaseline />

      {/* 4. Pass darkMode and setDarkMode down as properties (props).
        This makes them globally accessible down your component tree to the Settings file.
      */}
      <App darkMode={darkMode} setDarkMode={setDarkMode} />
    </ThemeProvider>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <Root />
  </React.StrictMode>,
);
